export function addNumbers(a: number, b: number): number {
  // Validate inputs are finite numbers
  if (!Number.isFinite(a) || !Number.isFinite(b)) {
    throw new TypeError('addNumbers: both arguments must be finite numbers');
  }

  // Guard against unsafe integer inputs that might cause precision loss
  const max = Number.MAX_SAFE_INTEGER;
  if (Math.abs(a) > max || Math.abs(b) > max) {
    throw new RangeError('addNumbers: input magnitude exceeds Number.MAX_SAFE_INTEGER');
  }

  return a + b;
}


