import { addNumbers } from '../src';

describe('addNumbers', () => {
  test('adds two positive numbers', () => {
    expect(addNumbers(2, 3)).toBe(5);
  });

  test('adds negative and positive number', () => {
    expect(addNumbers(-2, 5)).toBe(3);
  });

  test('throws on NaN input', () => {
    expect(() => addNumbers(NaN, 1)).toThrow(TypeError);
  });

  test('throws on Infinity input', () => {
    expect(() => addNumbers(Infinity, 1)).toThrow(TypeError);
  });

  test('throws when inputs exceed Number.MAX_SAFE_INTEGER', () => {
    expect(() => addNumbers(Number.MAX_SAFE_INTEGER + 1, 1)).toThrow(RangeError);
  });
});


